func solve(nums: Array<Int64>) -> Int64 {
    let n = nums.count
    var maxSum = Int64.min

    // Precompute prefix sums for quick range sum calculation
    var prefixSum = [Int64](repeating: 0, count: n + 1)
    for i in 0..<n {
        prefixSum[i + 1] = prefixSum[i] + nums[i]
    }

    // Precompute left increasing and right increasing segments
    var leftInc = [Bool](repeating: false, count: n)
    var rightInc = [Bool](repeating: false, count: n)

    // Compute left increasing segments (nums[l..p] is strictly increasing)
    for i in 1..<n {
        if nums[i] > nums[i - 1] {
            leftInc[i] = true
        }
    }

    // Compute right increasing segments (nums[q..r] is strictly increasing)
    for i in 0..<(n - 1) {
        if nums[i] < nums[i + 1] {
            rightInc[i] = true
        }
    }

    // Iterate all possible p and q positions
    for p in 1..<(n - 2) {
        for q in (p + 1)..<(n - 1) {
            // Check if nums[p..q] is strictly decreasing
            var isDec = true
            for i in p..<q {
                if nums[i] <= nums[i + 1] {
                    isDec = false
                    break
                }
            }
            if !isDec {
                continue
            }

            // Find the best l and r for current p and q
            // l can be from 0 to p-1, find the largest l where nums[l..p] is strictly increasing
            var l = p - 1
            while l >= 0 && leftInc[l + 1] {
                l -= 1
            }
            l += 1

            // r can be from q+1 to n-1, find the smallest r where nums[q..r] is strictly increasing
            var r = q + 1
            while r < n && rightInc[r - 1] {
                r += 1
            }
            r -= 1

            // Calculate the sum from l to r
            let currentSum = prefixSum[r + 1] - prefixSum[l]
            if currentSum > maxSum {
                maxSum = currentSum
            }
        }
    }

    return maxSum
}
