import Foundation

func solve(nums: Array<Int64>) -> Int64 {
    let n = nums.count
    var maxSum = Int64.min

    // Precompute prefix sums for quick range sum calculation
    var prefixSum = [Int64](repeating: 0, count: n + 1)
    for i in 0..<n {
        prefixSum[i + 1] = prefixSum[i] + nums[i]
    }

    // Precompute left increasing segments
    var left = [Int](repeating: 0, count: n)
    for i in 1..<n {
        if nums[i] > nums[i - 1] {
            left[i] = left[i - 1] + 1
        } else {
            left[i] = 0
        }
    }

    // Precompute right increasing segments
    var right = [Int](repeating: 0, count: n)
    for i in (0..<n-1).reversed() {
        if nums[i] < nums[i + 1] {
            right[i] = right[i + 1] + 1
        } else {
            right[i] = 0
        }
    }

    // Iterate through possible p and q positions
    for p in 1..<n-2 {
        for q in p+1..<n-1 {
            // Check if nums[l...p] is strictly increasing
            let l = p - left[p]
            if l >= p {
                continue
            }

            // Check if nums[q...r] is strictly increasing
            let r = q + right[q]
            if r <= q {
                continue
            }

            // Check if nums[p...q] is strictly decreasing
            var validDecreasing = true
            for i in p..<q {
                if nums[i] <= nums[i + 1] {
                    validDecreasing = false
                    break
                }
            }
            if !validDecreasing {
                continue
            }

            // Calculate the sum from l to r
            let currentSum = prefixSum[r + 1] - prefixSum[l]
            if currentSum > maxSum {
                maxSum = currentSum
            }
        }
    }

    return maxSum
}
